+fn collect_input_string(
+    input: PipelineData,
+    separator: &str,
+    config: &Config,
+) -> Result<String, ShellError> {
+    match input {
+        PipelineData::ByteStream(stream, ..) => {
+            if !stream.type_().is_string_coercible() {
+                return Err(ShellError::TypeMismatch {
+                    err_message: "expected string, but got binary".into(),
+                    span: stream.span(),
+                });
+            }
+
+            let span = stream.span();
+            match stream.into_child() {
+                Ok(child) => {
+                    let output = child.wait_with_output()?;
+                    let mut string =
+                        String::from_utf8(output.stdout.unwrap_or_default()).map_err(|err| {
+                            ShellError::NonUtf8Custom {
+                                span,
+                                msg: err.to_string(),
+                            }
+                        })?;
+                    trim_end_newline(&mut string);
+                    Ok(string)
+                }
+                Err(stream) => stream.into_string(),
+            }
+        }
+        input => input.collect_string(separator, config),
+    }
+}
+
+fn trim_end_newline(string: &mut String) {
+    if string.ends_with('\n') {
+        string.pop();
+        if string.ends_with('\r') {
+            string.pop();
+        }
+    }
+}
